int LowerBound(int[] a, int target) {
    int lo = 0, hi = a.Length;        // hi exclusive
    while (lo < hi) {
        int mid = lo + (hi - lo) / 2; // avoids overflow
        if (a[mid] < target) lo = mid + 1;
        else hi = mid;
    }
    return lo;                         // insertion point; == a.Length if none
}

